      if (argv.inputId !== undefined) setNestedValue(bodyData, ['input', 'id'], argv.inputId);
      if (argv.inputDomain !== undefined) setNestedValue(bodyData, ['input', 'domain'], argv.inputDomain);
      if (argv.inputOperator !== undefined) setNestedValue(bodyData, ['input', 'operator'], argv.inputOperator);
      if (argv.inputOsDistroName !== undefined)
        setNestedValue(bodyData, ['input', 'os_distro_name'], argv.inputOsDistroName);
      if (argv.inputOsDistroRevision !== undefined)
        setNestedValue(bodyData, ['input', 'os_distro_revision'], argv.inputOsDistroRevision);
      if (argv.inputOsVersionExtra !== undefined)
        setNestedValue(bodyData, ['input', 'os_version_extra'], argv.inputOsVersionExtra);
      if (argv.inputVersion !== undefined) setNestedValue(bodyData, ['input', 'version'], argv.inputVersion);
      if (argv.inputEnabled !== undefined) setNestedValue(bodyData, ['input', 'enabled'], argv.inputEnabled);
      if (argv.inputCheckDisks !== undefined) setNestedValue(bodyData, ['input', 'checkDisks'], argv.inputCheckDisks);
      if (argv.inputRequireAll !== undefined) setNestedValue(bodyData, ['input', 'requireAll'], argv.inputRequireAll);
      if (argv.inputCertificateId !== undefined)
        setNestedValue(bodyData, ['input', 'certificate_id'], argv.inputCertificateId);
